// Gera a lista de URLs OMIE para os últimos 30 dias
const dias = 30;
const hoje = new Date();
const items = [];

for (let i = dias; i >= 0; i--) {
  const d = new Date(hoje);
  d.setDate(d.getDate() - i);
  const ano = d.getFullYear();
  const mes = String(d.getMonth() + 1).padStart(2, '0');
  const dia = String(d.getDate()).padStart(2, '0');
  items.push({
    json: {
      url: `https://www.omie.es/en/file-download?parents=marginalpdbcpt&filename=marginalpdbcpt_${ano}${mes}${dia}.1`
    }
  });
}

return items;

// Agrega os 31 ficheiros OMIE num único item com a média
const todosPrecos = [];

for (const item of $input.all()) {
  const texto = item.json.data;
  if (!texto || typeof texto !== 'string') continue;
  for (const linha of texto.split('\n')) {
    const partes = linha.trim().split(';');
    // Formato OMIE: ANO;MES;DIA;HORA;PRECO_PT;PRECO_ES
    if (partes.length >= 5 && /^\d{4}$/.test(partes[0].trim())) {
      const preco = parseFloat(partes[4].replace(',', '.'));
      if (!isNaN(preco)) todosPrecos.push(preco);
    }
  }
}

if (todosPrecos.length === 0) {
  return [{ json: { erro: 'Sem dados OMIE disponíveis' } }];
}

const media = todosPrecos.reduce((a, b) => a + b, 0) / todosPrecos.length;

return [{
  json: {
    media_omie_mwh: media,
    num_precos: todosPrecos.length
  }
}];

// ╔══════════════════════════════════════════════════════════════════╗
// ║                      ⚙️  CONFIGURAÇÃO                            ║
// ║              Só precisas de editar esta secção                   ║
// ╚══════════════════════════════════════════════════════════════════╝

const CONFIG = {

  // ── Consumo e contrato ──────────────────────────────────────────
  consumo_kwh:  700,    // kWh/mês
  dias:          30,    // dias do período de faturação
  potencia_kva:  6.90,  // kVA contratados (filtra tarifários do CSV)
  ciclo: "Simples",     // "Simples" | "Bi-horário" | "Tri-horário"

  // ── Tarifário FIXO ──────────────────────────────────────────────
  // null  → escolhe automaticamente o mais barato do CSV do Tiago Felícia
  // {...} → usa estes valores directamente (ignora o CSV)
  //
  // ATENÇÃO: os valores do CSV já incluem TAR (tar_incluida = true na maioria).
  // Se colocares valores manuais, usa os valores FINAIS da tua fatura
  // (ou seja, com TAR e TSE já incluídas), e coloca tar_ja_incluida: true.
  //
  // Exemplo manual:
  // fixo_manual: {
  //   nome:           "G9 | Vantagem+",
  //   energia_kwh:    0.1348,  // valor bruto do CSV (inclui TAR + TSE)
  //   potencia_dia:   0.4498,  // valor bruto do CSV (inclui TAR)
  //   tar_en_incluida:  true,
  //   tar_pot_incluida: true,
  //   tse_incluida:     true,
  // },
  fixo_manual: null,

  // ── Filtros para escolha automática do melhor fixo ──────────────
  // (irrelevante se fixo_manual estiver preenchido)
  // Usa string vazia "" para ignorar esse filtro.
  filtros: {
    segmento:  "Residencial",     // "Residencial" | "Empresarial" | ""
    faturacao: "eletrónica",      // palavra parcial (ex: "eletrónica", "papel")
    pagamento: "Débito",          // palavra parcial (ex: "Débito", "Multibanco")
  },

  // ── Tarifário INDEXADO (OMIE) ────────────────────────────────────
  // Valores específicos do contrato indexado.
  // A TAR e TSE são SEMPRE adicionadas por cima no indexado (não estão incluídas).
  indexado: {
    nome:       "G9 | Smart Index",
    // Margem do comercializador em €/kWh (G9_CGS + G9_AC do contrato)
    margem_kwh: 0.0150,
    // Fator de perdas de rede (G9_FA — tipicamente entre 1.0 e 1.20)
    // Verifica no teu contrato. G9 usa ~1.16 no período de inverno.
    // Se não souberes, usa 1.0 para estimativa conservadora.
    fator_perdas: 1.0,
  },

  // ── Tarifas reguladas ERSE 2026 ──────────────────────────────────
  // Atualizar anualmente em Janeiro.
  // Fonte: https://www.tiagofelicia.pt/tarifas-acesso-redes.html
  tar: {
    energia_kwh:  0.0607,   // €/kWh — tarifa simples BTN
    potencia_dia: 0.3436,   // €/dia — para 6.9 kVA (alterar se mudares de potência)
  },

};

// ╔══════════════════════════════════════════════════════════════════╗
// ║          NÃO É NECESSÁRIO EDITAR ABAIXO DAQUI                   ║
// ╚══════════════════════════════════════════════════════════════════╝

// Constantes reguladas ERSE 2026 (não mudam a meio do ano)
const TSE = 0.0026;  // €/kWh — financiamento Tarifa Social Electricidade

const r4 = (v) => Math.round(v * 10000) / 10000;
const r2 = (v) => Math.round(v * 100) / 100;

// ── Normalização de texto para comparações ─────────────────────
const norm = (s) => (s || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

// ── Parser CSV robusto (lida com campos entre aspas) ────────────
function parseCSVLine(linha) {
  const cols = [];
  let cur = '';
  let inQ = false;
  for (const ch of linha) {
    if (ch === '"') { inQ = !inQ; }
    else if (ch === ',' && !inQ) { cols.push(cur.trim()); cur = ''; }
    else { cur += ch; }
  }
  cols.push(cur.trim());
  return cols;
}

const parseBool = (v) => {
  const s = (v || '').toLowerCase().trim();
  return s === 'true' || s === 'sim' || s === '1';
};
const parseNum = (v) => parseFloat((v || '0').replace(',', '.')) || 0;

// ── Leitura dos dados dos nós anteriores ───────────────────────
const omieData = $('Agregar OMIE').first().json;
if (omieData.erro) {
  return [{ json: { erro: omieData.erro } }];
}

const mediaOmie_MWh = omieData.media_omie_mwh; // €/MWh
const mediaOmie_kWh = mediaOmie_MWh / 1000;    // €/kWh
const csvTexto = $input.first().json.data;

// ── Parse do CSV e cálculo do melhor fixo ──────────────────────
//
// Lógica idêntica ao simulador do Tiago Felícia (calculos.js):
//
// 1. Lê preco_energia_simples e preco_potencia_dia do CSV (valores brutos)
// 2. Se tar_incluida_energia=true → energia_comercial = bruto - TAR_en
//    Se tar_incluida_energia=false → energia_comercial = bruto
// 3. energia_final = energia_comercial + TAR_en + (tse_incluida ? 0 : TSE)
// 4. Mesmo processo para potência
// 5. Custo = energia_final * consumo + potencia_final * dias
//
function obterTarifarios(csvTexto) {
  const linhas = csvTexto.split('\n').map(l => l.trim()).filter(Boolean);
  if (linhas.length < 2) throw new Error('CSV vazio ou inválido');

  // Mapear cabeçalho → índice de coluna
  const cab = parseCSVLine(linhas[0]).map(c => c.replace(/"/g, '').trim().toLowerCase());
  const col = (nome) => cab.findIndex(c => c.includes(nome.toLowerCase()));

  // Índices das colunas relevantes (nomes do CSV do Tiago Felícia)
  const C = {
    comercializador: col('comercializador'),
    nome:            col('nome'),
    tipo:            col('tipo'),
    ciclo:           col('opcao_horaria'),
    potKva:          col('potencia_kva'),
    energia:         col('preco_energia_simples'),
    potDia:          col('preco_potencia_dia'),
    tarEnIncl:       col('tar_incluida_energia'),
    tarPotIncl:      col('tar_incluida_potencia'),
    tseIncl:         col('financiamento_tse'),
    segmento:        col('segmento'),
    faturacao:       col('faturacao'),
    pagamento:       col('pagamento'),
    descFatura:      col('desconto_fatura'),
  };

  const cicloChave = norm(CONFIG.ciclo).split('-')[0].split(' ')[0]; // "simples", "bi", "tri"

  const fixos = [];

  for (let i = 1; i < linhas.length; i++) {
    const cols = parseCSVLine(linhas[i]);
    if (cols.length < 10) continue;

    const tipo    = (cols[C.tipo]    || '').replace(/"/g, '').trim();
    const ciclo   = norm(cols[C.ciclo]   || '');
    const potKva  = parseNum(cols[C.potKva]);
    const segmento  = norm(cols[C.segmento]  || '');
    const faturacao = norm(cols[C.faturacao] || '');
    const pagamento = norm(cols[C.pagamento] || '');

    // ── Filtros obrigatórios ──
    if (norm(tipo) !== 'fixo') continue;
    if (Math.abs(potKva - CONFIG.potencia_kva) > 0.1) continue;
    if (!ciclo.includes(cicloChave)) continue;

    // ── Filtros opcionais ──
    const f = CONFIG.filtros;
    if (f.segmento === 'Residencial' && !segmento.includes('domestico')) continue;
    if (f.segmento === 'Empresarial' && !segmento.includes('nao domestico') && !segmento.includes('nao-domestico')) continue;
    if (f.faturacao && !faturacao.includes(norm(f.faturacao))) continue;
    if (f.pagamento && !pagamento.includes(norm(f.pagamento))) continue;

    // ── Leitura dos preços brutos ──
    const energiaBruta = parseNum(cols[C.energia]);
    const potDiaBruta  = parseNum(cols[C.potDia]);
    if (energiaBruta <= 0 || potDiaBruta <= 0) continue;

    const tarEnIncl  = parseBool(cols[C.tarEnIncl]);
    const tarPotIncl = parseBool(cols[C.tarPotIncl]);
    const tseIncl    = parseBool(cols[C.tseIncl]);

    // ── Normalização exacta (igual ao simulador) ──
    // Extrai componente comercial (sem TAR)
    const energiaComercial = tarEnIncl
      ? energiaBruta - CONFIG.tar.energia_kwh
      : energiaBruta;

    const potComercial = tarPotIncl
      ? potDiaBruta - CONFIG.tar.potencia_dia
      : potDiaBruta;

    // Re-adiciona TAR regulada + TSE se não incluída
    const energiaFinal = energiaComercial + CONFIG.tar.energia_kwh + (tseIncl ? 0 : TSE);
    const potFinal     = potComercial     + CONFIG.tar.potencia_dia;

    // Desconto de fatura (se existir)
    const descFatura = parseNum(cols[C.descFatura] || '0');
    const descTotal  = descFatura * (CONFIG.dias / 30); // proporcional

    const custoEnergia = energiaFinal * CONFIG.consumo_kwh;
    const custoPot     = potFinal     * CONFIG.dias;
    const custoTotal   = custoEnergia + custoPot - descTotal;

    fixos.push({
      comercializador:  (cols[C.comercializador] || '').replace(/"/g, '').trim(),
      nome:             (cols[C.nome]            || '').replace(/"/g, '').trim(),
      energia_kwh:      r4(energiaFinal),
      potencia_dia:     r4(potFinal),
      energia_comercial_kwh: r4(energiaComercial),
      pot_comercial_dia:     r4(potComercial),
      desconto_mes:     descFatura,
      custo_estimado:   r2(custoTotal),
      tar_en_incl:      tarEnIncl,
      tar_pot_incl:     tarPotIncl,
      tse_incl:         tseIncl,
    });
  }

  if (fixos.length === 0) {
    throw new Error(
      `Nenhum tarifário fixo encontrado para ${CONFIG.potencia_kva} kVA / ` +
      `${CONFIG.ciclo} com filtros: ${JSON.stringify(CONFIG.filtros)}`
    );
  }

  fixos.sort((a, b) => a.custo_estimado - b.custo_estimado);
  return fixos;
}

// ── Obter melhor fixo ──────────────────────────────────────────
let melhorFixo;
let fonte;

if (CONFIG.fixo_manual) {
  // Manual: normaliza da mesma forma
  const m = CONFIG.fixo_manual;
  const tarEnIncl  = m.tar_en_incluida !== false;
  const tarPotIncl = m.tar_pot_incluida !== false;
  const tseIncl    = m.tse_incluida !== false;

  const energiaComercial = tarEnIncl ? m.energia_kwh - CONFIG.tar.energia_kwh : m.energia_kwh;
  const potComercial     = tarPotIncl ? m.potencia_dia - CONFIG.tar.potencia_dia : m.potencia_dia;
  const energiaFinal     = energiaComercial + CONFIG.tar.energia_kwh + (tseIncl ? 0 : TSE);
  const potFinal         = potComercial + CONFIG.tar.potencia_dia;

  melhorFixo = {
    nome:          m.nome,
    comercializador: '',
    energia_kwh:   r4(energiaFinal),
    potencia_dia:  r4(potFinal),
    custo_estimado: r2(energiaFinal * CONFIG.consumo_kwh + potFinal * CONFIG.dias),
  };
  fonte = 'manual';
} else {
  let todos;
  try {
    todos = obterTarifarios(csvTexto);
  } catch (e) {
    return [{ json: { erro: e.message } }];
  }
  melhorFixo = todos[0];
  fonte = 'automatico (CSV Tiago Felícia)';
}

// ── Cálculo do custo indexado ──────────────────────────────────
//
// Lógica do simulador para G9 Smart Index (e equivalentes):
//   preço_kwh = OMIE_€/kWh * fator_perdas + margem + TAR_energia + TSE
//   custo     = preço_kwh * consumo + TAR_potencia * dias
//
// A TAR e TSE são SEMPRE adicionadas no indexado (tar_e_incl = false no CSV)
// O fator_perdas compensa as perdas de rede (varia ~1.10-1.20 conforme contrato)
//
const precoKwhIndexado = (
  mediaOmie_kWh * CONFIG.indexado.fator_perdas
  + CONFIG.indexado.margem_kwh
  + CONFIG.tar.energia_kwh
  + TSE
);
const custoIndexado = (
  CONFIG.consumo_kwh * precoKwhIndexado
  + CONFIG.dias * CONFIG.tar.potencia_dia
);

// ── Break-even (a partir de que OMIE o fixo é mais barato) ─────
//
// Resolve: custo_fixo = custo_indexado
// melhorFixo.custo = consumo * (OMIE_kWh * perdas + margem + TAR + TSE) + dias * TAR_pot
// OMIE_kWh_breakeven = (custo_fixo/consumo - margem - TAR - TSE) / perdas
//
const custoFixo = melhorFixo.custo_estimado;
const breakeven_kWh = (
  (custoFixo - CONFIG.dias * CONFIG.tar.potencia_dia) / CONFIG.consumo_kwh
  - CONFIG.indexado.margem_kwh
  - CONFIG.tar.energia_kwh
  - TSE
) / CONFIG.indexado.fator_perdas;
const breakeven_MWh = r2(breakeven_kWh * 1000);

const poupanca   = r2(Math.abs(custoFixo - custoIndexado));
const fixoMaisBarato = custoFixo <= r2(custoIndexado);
const recomendacao   = fixoMaisBarato ? melhorFixo.nome : CONFIG.indexado.nome;

// ── Resumo formatado ───────────────────────────────────────────
const data = new Date().toLocaleDateString('pt-PT');
const maisBaratoLabel = fixoMaisBarato
  ? `🏆 FIXO mais barato — poupa ${poupanca}€`
  : `🏆 INDEXADO mais barato — poupa ${poupanca}€`;

let resumo = `📊 *ANÁLISE OMIE* (${data})\n`;
resumo += `━━━━━━━━━━━━━━━━━━━━\n\n`;
resumo += `⚡ *MERCADO OMIE (últimos 30 dias):*\n`;
resumo += `• Média: *${r2(mediaOmie_MWh)} €/MWh*\n`;
resumo += `• Break-even: ${breakeven_MWh} €/MWh\n\n`;
resumo += `🔒 *MELHOR FIXO (${fonte}):*\n`;
resumo += `• ${melhorFixo.nome}\n`;
resumo += `• Energia: ${melhorFixo.energia_kwh} €/kWh | Potência: ${melhorFixo.potencia_dia} €/dia\n`;
resumo += `• Custo estimado: *${custoFixo}€*\n\n`;
resumo += `📈 *INDEXADO (${CONFIG.indexado.nome}):*\n`;
resumo += `• Preço kWh: ${r4(precoKwhIndexado)} €/kWh\n`;
resumo += `• Custo estimado: *${r2(custoIndexado)}€*\n\n`;
resumo += `━━━━━━━━━━━━━━━━━━━━\n`;
resumo += `💡 *${maisBaratoLabel}*\n`;
resumo += `   Recomendação: *${recomendacao}*`;

return [{
  json: {
    data_analise:              data,
    media_omie_eur_mwh:        r2(mediaOmie_MWh),
    breakeven_eur_mwh:         breakeven_MWh,
    omie_acima_breakeven:      mediaOmie_MWh > breakeven_MWh,
    // Melhor fixo
    melhor_fixo_nome:          melhorFixo.nome,
    melhor_fixo_comercializador: melhorFixo.comercializador || '',
    melhor_fixo_fonte:         fonte,
    melhor_fixo_energia_kwh:   melhorFixo.energia_kwh,
    melhor_fixo_potencia_dia:  melhorFixo.potencia_dia,
    custo_melhor_fixo_eur:     custoFixo,
    // Indexado
    indexado_nome:             CONFIG.indexado.nome,
    indexado_preco_kwh:        r4(precoKwhIndexado),
    custo_indexado_eur:        r2(custoIndexado),
    // Comparação
    poupanca_eur:              poupanca,
    recomendacao:              recomendacao,
    fixo_mais_barato:          fixoMaisBarato,
    num_precos_omie:           omieData.num_precos,
    resumo,
  }
}];
